158	        free(element->value);
159	        //INFO("Cannot allocate memory for key");
160	      }
161	
162	      free(element);
163	      return -1; //No Memory
164	    }
165	  } else if (table->mode == MODE_VALUEREF) {
166	    //LOG("Adding a key-value pair to the hash table with hash -> %d, in VALUEREF MODE", (int)hash);
167	    element->key = malloc(key_len);
168	
169	    if (element->key) {
170	      memcpy(element->key, key, key_len);
171	    } else {
172	      //INFO("Cannot allocate memory for key");
173	      free(element);
174	      return -1; //No Memory
