          hash_table_element_t *to_delete = temp->next;
          temp->next = element;
          element->next = to_delete->next;
          hash_table_element_delete(table, to_delete);
          // since we are replacing values no need to change key_count
          return 0;
        } else {
          temp = temp->next;
        }
      }
    }

    temp->next = element;
    table->key_count++;
  }

