  size_t count;
  size_t i;
  int result = 0;

  // Save original state before any modifications
  hash_table_element_t **original_store_house = table->store_house;
  size_t original_key_num = table->key_num;
  size_t original_key_count = table->key_count;
  hash_table_mode_t original_mode = table->mode;

