      table->key_num = original_key_num;
      table->key_count = original_key_count;
      table->mode = original_mode;

      // Clean up elements array
      free(elements);

      return -3;
    }
  }

  // Restore original mode
  table->mode = original_mode;

  // Free old store house
  free(original_store_house);

